CustomField.formula:
( /* テキスト（空白のみは未入力） */ IF(LEN(TRIM(Name)) > 0, 1, 0) + IF(LEN(TRIM(SL_daihyousya__c)) > 0, 1, 0) + IF(LEN(TRIM(SL_HPURL__c)) > 0, 1, 0) + IF(LEN(TRIM(JU_Score2__c)) > 0, 1, 0) + IF(LEN(TRIM(JU_sakuzutaiseigaityusaki__c)) > 0, 1, 0) + IF(LEN(TRIM(JU_sinseigyoumugaityusaki__c)) > 0, 1, 0) + /* 設立年（テキスト）："0" もカウント */ IF(LEN(TRIM(dx_setsuritsunen__c)) > 0, 1, 0) +
/* 単一選択（None/--None--は未入力扱い） */ IF(AND(NOT(ISBLANK(TEXT(JU_AccountType__c))), TEXT(JU_AccountType__c) <> "None", TEXT(JU_AccountType__c) <> "--None--"),1,0) + IF(AND(NOT(ISBLANK(TEXT(JU_HeadquartersLocation__c))), TEXT(JU_HeadquartersLocation__c) <> "None", TEXT(JU_HeadquartersLocation__c) <> "--None--"),1,0) + IF(AND(NOT(ISBLANK(TEXT(JU_TG__c))), TEXT(JU_TG__c) <> "None", TEXT(JU_TG__c) <> "--None--"),1,0) + IF(AND(NOT(ISBLANK(TEXT(JU_consept__c))), TEXT(JU_consept__c) <> "None", TEXT(JU_consept__c) <> "--None--"),1,0) + IF(AND(NOT(ISBLANK(TEXT(JU_ThermalInsulationPerformance__c))), TEXT(JU_ThermalInsulationPerformance__c) <> "None", TEXT(JU_ThermalInsulationPerformance__c) <> "--None--"),1,0) + IF(AND(NOT(ISBLANK(TEXT(JU_PrimaryEnergyConsumption__c))), TEXT(JU_PrimaryEnergyConsumption__c) <> "None", TEXT(JU_PrimaryEnergyConsumption__c) <> "--None--"),1,0) + IF(AND(NOT(ISBLANK(TEXT(JU_CAD__c))), TEXT(JU_CAD__c) <> "None", TEXT(JU_CAD__c) <> "--None--"),1,0) + IF(AND(NOT(ISBLANK(TEXT(JU_sakuzutaisei__c))), TEXT(JU_sakuzutaisei__c) <> "None", TEXT(JU_sakuzutaisei__c) <> "--None--"),1,0) + IF(AND(NOT(ISBLANK(TEXT(JU_sinseigyoumu__c))), TEXT(JU_sinseigyoumu__c) <> "None", TEXT(JU_sinseigyoumu__c) <> "--None--"),1,0) + IF(AND(NOT(ISBLANK(TEXT(JU_StructuralCalculation__c))), TEXT(JU_StructuralCalculation__c) <> "None", TEXT(JU_StructuralCalculation__c) <> "--None--"),1,0) +
/* 複数選択（TEXT不可。空でなければ1） */ IF(NOT(ISBLANK(Ju_zyuutakutenkaiarea__c)),1,0) + IF(NOT(ISBLANK(Ju_target_area__c)),1,0) +
/* 電話 */ IF(NOT(ISBLANK(Phone)),1,0) +
/* 数値／通貨／パーセント（空欄は0カウント、0は1カウント） */ IF(NOT(ISBLANK(NumberOfEmployees)),1,0) + IF(NOT(ISBLANK(ClosingMonth__c)),1,0) + IF(NOT(ISBLANK(JU_AccountSales__c)),1,0) + IF(NOT(ISBLANK(Ju_yoshingendogaku__c)),1,0) + IF(NOT(ISBLANK(JU_NumberOfConstructionStartsPerYear__c)),1,0) + IF(NOT(ISBLANK(JU_NumberOfConstructionStartsInTheArea__c)),1,0) + IF(NOT(ISBLANK(Ju_bunjou__c)),1,0) + IF(NOT(ISBLANK(Ju_chuumon__c)),1,0) + IF(NOT(ISBLANK(Ju_chintai__c)),1,0) + IF(NOT(ISBLANK(JU_Contract__c)),1,0) + IF(NOT(ISBLANK(Ju_zairai__c)),1,0) + IF(NOT(ISBLANK(Ju_2_4__c)),1,0) + IF(NOT(ISBLANK(Ju_sdukuri__c)),1,0) + IF(NOT(ISBLANK(Ju_RC__c)),1,0) + IF(NOT(ISBLANK(JU_prefabricated__c)),1,0) +
/* チェックボックス（TRUEなら1） */ IF(JU_AccountOpening__c,1,0) + IF(CheckJU_CustomerFeaturesFutureEfforts__c,1,0) +
/* 住所（いずれか入っていれば1） */ IF( NOT( ISBLANK(BillingStreet) && ISBLANK(BillingCity) && ISBLANK(BillingState) && ISBLANK(BillingPostalCode) && ISBLANK(BillingCountry) ), 1,0 ) )
